namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    IReadOnlyList<Department> GetDepartments();
    Department? GetDepartment(int id);
    IReadOnlyList<Course> GetCourses(string? search = null, int? departmentId = null);
    IReadOnlyList<Course> GetFeaturedCourses();
    Course? GetCourse(int id);
    bool SubmitEnrollment(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "The science of numbers, quantity, and space." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Literature, writing, and language studies." },
        new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and human civilizations." },
    ];

    private static readonly List<Course> Courses =
    [
        new() { Id = 1, Title = "Introduction to Programming", Code = "CS 101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control structures, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses. She holds a PhD from MIT and specializes in CS education research.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 2, Title = "Data Structures & Algorithms", Code = "CS 201", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques. Emphasis on time and space complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Prof. James Rodriguez", InstructorBio = "Prof. Rodriguez is an ACM Distinguished Educator with research interests in algorithm optimization and competitive programming.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
        new() { Id = 3, Title = "Database Systems", Code = "CS 340", Description = "Introduction to database design, SQL, normalization, transaction processing, and modern NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Amara Okafor", InstructorBio = "Dr. Okafor spent a decade in industry at Oracle and MongoDB before joining academia. Her research focuses on distributed database systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
        new() { Id = 4, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning instructor known for making calculus accessible. He has authored two widely-used textbooks.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
        new() { Id = 5, Title = "Linear Algebra", Code = "MATH 220", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Prof. Elena Volkov", InstructorBio = "Prof. Volkov's research spans pure and applied linear algebra with publications in numerical methods.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
        new() { Id = 6, Title = "Discrete Mathematics", Code = "MATH 250", Description = "Logic, sets, relations, functions, combinatorics, graph theory, and proof techniques.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning instructor known for making calculus accessible. He has authored two widely-used textbooks.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
        new() { Id = 7, Title = "General Physics I", Code = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Calculus-based introductory physics with laboratory.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Lab Fri 1:00–3:50 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an experimental physicist whose work on fluid dynamics has been published in Nature Physics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
        new() { Id = 8, Title = "Electromagnetism", Code = "PHYS 202", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Mon/Wed 10:00–11:20 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Prof. Lisa Nakamura", InstructorBio = "Prof. Nakamura is a theoretical physicist specializing in quantum electrodynamics and photonics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
        new() { Id = 9, Title = "English Composition", Code = "ENG 101", Description = "Develop critical thinking and writing skills through essay composition, rhetoric analysis, and peer review.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Prof. David Walsh", InstructorBio = "Prof. Walsh is a published novelist and essayist who brings creative writing techniques to academic composition.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
        new() { Id = 10, Title = "American Literature", Code = "ENG 250", Description = "Survey of American literary works from the colonial period through the 21st century.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Angela Morrison", InstructorBio = "Dr. Morrison specializes in African American literature and has received the National Book Critics Circle award for criticism.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
        new() { Id = 11, Title = "World History to 1500", Code = "HIST 101", Description = "Survey of major civilizations, cultures, and events from prehistory through the late medieval period.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", InstructorName = "Dr. Fatima Al-Hassan", InstructorBio = "Dr. Al-Hassan is a specialist in ancient Mediterranean and Islamic civilizations with extensive fieldwork experience.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        new() { Id = 12, Title = "Modern World History", Code = "HIST 102", Description = "From the Renaissance through the present day: exploration, revolution, industrialization, and globalization.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Prof. Thomas Bennett", InstructorBio = "Prof. Bennett is a historian of modern Europe and the author of several books on 20th-century geopolitics.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
    ];

    public IReadOnlyList<Department> GetDepartments() => Departments;

    public Department? GetDepartment(int id) => Departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = Courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() => Courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => Courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollment(EnrollmentRequest request) => true;
}

